 1	import * as React from 'react';
 2	import { useFetchCsv } from '@odf/shared/hooks/use-fetch-csv';
 3	import { OverviewDetailItem as DetailItem } from '@odf/shared/overview-page';
 4	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 5	import { getOprVersionFromCSV } from '@odf/shared/utils';
 6	import {
 7	  Card,
 8	  CardHeader,
 9	  CardTitle,
10	  CardBody,
11	  DescriptionList,
12	} from '@patternfly/react-core';
13	import { CLIENT_OPERATOR } from '../../../constants';
14	
15	export const DetailsCard: React.FC = () => {
16	  const { t } = useCustomTranslation();
17	
18	  const [csv, csvLoaded, csvError] = useFetchCsv({
19	    specName: CLIENT_OPERATOR,
20	  });
21	
22	  const subscriptionVersion = getOprVersionFromCSV(csv);
23	
24	  const serviceName = t('Data Foundation');
25	
26	  return (
27	    <Card>
28	      <CardHeader>
29	        <CardTitle>{t('Details')}</CardTitle>
30	      </CardHeader>
31	      <CardBody>
32	        <DescriptionList>
33	          <DetailItem key="service_name" title={t('Service name')}>
34	            {serviceName}
35	          </DetailItem>
36	          <DetailItem key="mode" title={t('Mode')}>
37	            {t('Client')}
38	          </DetailItem>
39	          <DetailItem
40	            key="version"
41	            title={t('Version')}
42	            isLoading={!csvLoaded}
43	            error={csvError?.message}
44	            data-test-id="cluster-subscription"
45	          >
46	            {subscriptionVersion}
47	          </DetailItem>
48	        </DescriptionList>
49	      </CardBody>
50	    </Card>
51	  );
52	};
53	
54	export default DetailsCard;

